int d = Long.toString(n).length();
long[] pow10 = new long[20];
pow10[0] = 1;
for (int i = 1; i < 20; i++) {
    pow10[i] = pow10[i - 1] * 10;
}

// Count palindromes with fewer digits than n
for (int len = 1; len < d; len++) {
    int k = (len - 1) / 2;
    long m = pow10[k];
    odd += 5 * m;
    even += 4 * m;
}

// Count palindromes with same number of digits as n
int halfLen = (d + 1) / 2;
long lower = pow10[halfLen - 1];
long upper = n / pow10[d / 2];

// All palindromes formed by prefixes in [lower, upper-1] are guaranteed <= n
if (upper > lower) {
    for (int first = 1; first <= 9; first++) {
        long segStart = first * pow10[halfLen - 1];
        long segEnd = (first + 1) * pow10[halfLen - 1] - 1;
        long start = Math.max(lower, segStart);
        long end = Math.min(upper - 1, segEnd);
        if (start <= end) {
            long cnt = end - start + 1;
            if ((first & 1) == 1) {
                odd += cnt;
            } else {
                even += cnt;
            }
        }
    }
}

// Check the boundary prefix (upper)
String s = Long.toString(upper);
String rev = new StringBuilder(s).reverse().toString();
long pal;
if (d % 2 == 0) {
    pal = Long.parseLong(s + rev);
} else {
    pal = Long.parseLong(s + rev.substring(1));
}
if (pal <= n) {
    int firstDigit = (int) (upper / pow10[halfLen - 1]);
    if ((firstDigit & 1) == 1) {
        odd++;
    } else {
        even++;
    }
}

return Pair.with(even, odd);

